    private static int[] decodeIntArray(String[] chunks) {
        StringBuilder builder = new StringBuilder();
        for (String chunk : chunks) {
            builder.append(chunk);
        }
        byte[] bytes = Base64.getDecoder().decode(builder.toString());
        if (bytes.length % Integer.BYTES != 0) {
            throw new IllegalStateException("Invalid Java 11 entry order byte length: " + bytes.length);
        }
        ByteBuffer buffer = ByteBuffer.wrap(bytes).order(ByteOrder.BIG_ENDIAN);
        int[] values = new int[bytes.length / Integer.BYTES];
        for (int i = 0; i < values.length; i++) {
            values[i] = buffer.getInt();
        }
        if (values.length != ENTRY_COUNT) {
            throw new IllegalStateException("Invalid Java 11 entry order size: " + values.length);
        }
        return values;
    }
